mapper.select:
select count(*)
  from board_user_read
 where board_id = #{boardId}
   and user_seq = #{userSeq};

mapper.update:
update board
   set read_count = read_count + 1
 where board_id = #{boardId};

update board
   set title = #{title},
       content = #{content} 
 where board_id = #{boardId};
